            KeyStore keyStore = KeyStore.getInstance(KEYSTORE_PROVIDER);
            keyStore.load(null);
            SecretKey secretKey = (SecretKey) keyStore.getKey(KEY_ALIAS, null);

            byte[] iv = Base64.decode(encryptedData.getIv(), Base64.NO_WRAP);
            byte[] encryptedBytes = Base64.decode(encryptedData.getCiphertext(), Base64.NO_WRAP);

