package com.securebank.app.model;

import java.math.BigDecimal;

public class TransactionRequest {
    private String sourceAccountId;
    private String destinationAccountId;
    private BigDecimal amount;
    private String currency;
    private Transaction.TransactionType type;
    private String description;
    private String idempotencyToken;

    public TransactionRequest() {}

    // Builder pattern for safe construction
    public static class Builder {
        private final TransactionRequest request;

        public Builder() {
            request = new TransactionRequest();
        }

        public Builder sourceAccount(String accountId) {
            request.sourceAccountId = accountId;
            return this;
        }

        public Builder destinationAccount(String accountId) {
            request.destinationAccountId = accountId;
            return this;
        }

        public Builder amount(BigDecimal amount) {
            request.amount = amount;
            return this;
        }

        public Builder currency(String currency) {
            request.currency = currency;
            return this;
        }

        public Builder type(Transaction.TransactionType type) {
            request.type = type;
            return this;
        }

        public Builder description(String description) {
            request.description = description;
            return this;
        }

        public Builder idempotencyToken(String token) {
            request.idempotencyToken = token;
            return this;
        }

        public TransactionRequest build() {
            validate();
            return request;
        }

        private void validate() {
            if (request.sourceAccountId == null || request.sourceAccountId.isEmpty()) {
                throw new IllegalArgumentException("Source account is required");
            }
            if (request.amount == null || request.amount.compareTo(BigDecimal.ZERO) <= 0) {
                throw new IllegalArgumentException("Amount must be positive");
            }
            if (request.amount.scale() > 2) {
                throw new IllegalArgumentException("Amount cannot have more than 2 decimal places");
            }
            if (request.amount.compareTo(new BigDecimal("1000000")) > 0) {
                throw new IllegalArgumentException("Amount exceeds maximum transaction limit");
            }
            if (request.type == null) {
                throw new IllegalArgumentException("Transaction type is required");
            }
            if (request.type == Transaction.TransactionType.TRANSFER
                    && (request.destinationAccountId == null || request.destinationAccountId.isEmpty())) {
                throw new IllegalArgumentException("Destination account required for transfers");
            }
            if (request.sourceAccountId.equals(request.destinationAccountId)) {
                throw new IllegalArgumentException("Source and destination cannot be the same");
            }
            if (request.currency == null || request.currency.isEmpty()) {
                request.currency = "USD";
            }
            // Sanitize description
            if (request.description != null) {
                request.description = InputValidator.sanitize(request.description);
            }
        }
    }

    public String getSourceAccountId() { return sourceAccountId; }
    public String getDestinationAccountId() { return destinationAccountId; }
    public BigDecimal getAmount() { return amount; }
    public String getCurrency() { return currency; }
    public Transaction.TransactionType getType() { return type; }
    public String getDescription() { return description; }
    public String getIdempotencyToken() { return idempotencyToken; }
}

