package com.securebank.app.model;

import java.math.BigDecimal;
import java.util.regex.Pattern;

public class InputValidator {

    private static final Pattern ACCOUNT_ID_PATTERN = Pattern.compile("^[a-zA-Z0-9\\-]{1,64}$");
    private static final Pattern ACCOUNT_NUMBER_PATTERN = Pattern.compile("^[0-9]{8,20}$");
    private static final Pattern AMOUNT_PATTERN = Pattern.compile("^\\d{1,10}(\\.\\d{1,2})?$");
    private static final Pattern DESCRIPTION_PATTERN = Pattern.compile("^[a-zA-Z0-9\\s.,\\-#]{0,256}$");
    private static final Pattern CURRENCY_PATTERN = Pattern.compile("^[A-Z]{3}$");

    public static boolean isValidAccountId(String accountId) {
        return accountId != null && ACCOUNT_ID_PATTERN.matcher(accountId).matches();
    }

    public static boolean isValidAccountNumber(String accountNumber) {
        return accountNumber != null && ACCOUNT_NUMBER_PATTERN.matcher(accountNumber).matches();
    }

    public static boolean isValidAmount(String amountStr) {
        if (amountStr == null || !AMOUNT_PATTERN.matcher(amountStr).matches()) {
            return false;
        }
        try {
            BigDecimal amount = new BigDecimal(amountStr);
            return amount.compareTo(BigDecimal.ZERO) > 0
                    && amount.compareTo(new BigDecimal("1000000")) <= 0;
        } catch (NumberFormatException e) {
            return false;
        }
    }

    public static boolean isValidDescription(String description) {
        return description == null || DESCRIPTION_PATTERN.matcher(description).matches();
    }

    public static boolean isValidCurrency(String currency) {
        return currency != null && CURRENCY_PATTERN.matcher(currency).matches();
    }

    public static String sanitize(String input) {
        if (input == null) return null;
        // Remove any potentially dangerous characters
        return input.replaceAll("[^a-zA-Z0-9\\s.,\\-#]", "").trim();
    }

    public static BigDecimal parseAmount(String amountStr) {
        if (!isValidAmount(amountStr)) {
            throw new IllegalArgumentException("Invalid amount format");
        }
        return new BigDecimal(amountStr).setScale(2, BigDecimal.ROUND_HALF_UP);
    }
}

