package com.securebank.app.model;

public class TransactionResult<T> {

    public enum Status {
        SUCCESS,
        ERROR,
        SESSION_EXPIRED,
        NETWORK_ERROR,
        VALIDATION_ERROR,
        SECURITY_ERROR
    }

    private final Status status;
    private final T data;
    private final String errorMessage;
    private final String errorCode;

    private TransactionResult(Status status, T data, String errorMessage, String errorCode) {
        this.status = status;
        this.data = data;
        this.errorMessage = errorMessage;
        this.errorCode = errorCode;
    }

    public static <T> TransactionResult<T> success(T data) {
        return new TransactionResult<>(Status.SUCCESS, data, null, null);
    }

    public static <T> TransactionResult<T> error(String message, String code) {
        return new TransactionResult<>(Status.ERROR, null, message, code);
    }

    public static <T> TransactionResult<T> sessionExpired() {
        return new TransactionResult<>(Status.SESSION_EXPIRED, null,
                "Session has expired. Please log in again.", "SESSION_EXPIRED");
    }

    public static <T> TransactionResult<T> networkError() {
        return new TransactionResult<>(Status.NETWORK_ERROR, null,
                "Network error. Please check your connection.", "NETWORK_ERROR");
    }

    public static <T> TransactionResult<T> validationError(String message) {
        return new TransactionResult<>(Status.VALIDATION_ERROR, null, message, "VALIDATION_ERROR");
    }

    public static <T> TransactionResult<T> securityError(String message) {
        return new TransactionResult<>(Status.SECURITY_ERROR, null, message, "SECURITY_ERROR");
    }

    public boolean isSuccess() { return status == Status.SUCCESS; }
    public Status getStatus() { return status; }
    public T getData() { return data; }
    public String getErrorMessage() { return errorMessage; }
    public String getErrorCode() { return errorCode; }
}

